package genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter.service.VehicleFilterService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/vehicle-filters") public class VehicleFilterController { private final VehicleFilterService service; public VehicleFilterController(VehicleFilterService service){this.service=service;} @GetMapping public List<VehicleFilterResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public VehicleFilterResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleFilterResponse create(@RequestBody VehicleFilterUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleFilterResponse update(@PathVariable UUID id,@RequestBody VehicleFilterUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
